const reports = $json.reports || [];

const hoje = new Date();

const dataFormatada = hoje.toLocaleDateString('pt-BR', {
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
});

function clean(value) {
  return String(value || '')
    .replace(/<b>/g, '**')
    .replace(/<\/b>/g, '**')
    .replace(/<br\s*\/?>/g, '\n')
    .trim();
}

function limit(value, max) {
  const text = clean(value);
  if (text.length <= max) return text;
  return text.substring(0, max - 3) + '...';
}

if ($json.success === false) {
  return [
    {
      json: {
        embeds: [
          {
            title: '❌ Erro ao executar Apps Script',
            description: clean($json.error || $json.message || 'Erro desconhecido.'),
            color: 15158332,
            timestamp: hoje.toISOString(),
          },
        ],
      },
    },
  ];
}

if (!reports.length) {
  return [
    {
      json: {
        embeds: [
          {
            title: '⚠️ Nenhum relatório encontrado',
            description: clean($json.discordContent || $json.message || 'O Apps Script não retornou reports.'),
            color: 16776960,
            timestamp: hoje.toISOString(),
          },
        ],
      },
    },
  ];
}

const embeds = reports.map((report) => {
  const fields = [];

  for (const section of report.sections || []) {
    let value = '';

    for (const widget of section.widgets || []) {
      const d = widget.decoratedText || {};

      const nome = clean(d.text || '');
      const area = clean(d.topLabel || '');
      const info = clean(d.bottomLabel || '');

      if (nome) value += `${nome}\n`;
      if (area) value += `🏢 ${area}\n`;
      if (info) value += `${info}\n\n`;
    }

    if (value.trim()) {
      fields.push({
        name: limit(section.header || 'Informações', 256),
        value: limit(value.trim(), 1024),
        inline: false,
      });
    }
  }

  return {
    title:
      report.title === 'Escala de Trabalho'
        ? '📋 Escala de Trabalho'
        : '🏖️ Relatório de Ausências',
    description: `🗓️ ${dataFormatada}\n⏰ Atualização automática`,
    color: report.color || 3447003,
    fields: fields.slice(0, 25),
    footer: {
      text: 'Atualizado automaticamente pelo n8n',
    },
    timestamp: hoje.toISOString(),
  };
});

return [
  {
    json: {
      embeds,
    },
  },
];
